{"code": "import math

def find_battle_number(D):
    # Calculate N such that sum_{k=1}^N >= D and sum_{k=1}^{N-1} < D
    # Using the formula N = ceil( (sqrt(8D +1) -1)/2 )
    sqrt_val = math.sqrt(8 * D + 1)
    N = (sqrt_val - 1) / 2
    # Check if N is integer
    if N.is_integer():
        return int(N)
    else:
        return math.ceil(N)

T = int(input())
for _ in range(T):
    D = int(input())
    N = find_battle_number(D)
    remainder = N % 3
    if remainder == 0:
        print('SL')
    elif remainder == 1:
        print('LB')
    else:
        print('BS')"}

