    # Binary search to find the smallest N where N*(N+1)//2 >= D
    low = 1
    high = 2 * 10**5  # Sufficiently large upper bound
    while low < high:
        mid = (low + high) // 2
        if mid * (mid + 1) // 2 >= D:
            high = mid
        else:
            low = mid + 1
    return low

T = int(input())
for _ in range(T):
    D = int(input())
    N = find_battle_number(D)
    remainder = N % 3
    if remainder == 0:
        print('SL')
    elif remainder == 1:
        print('LB')
    else:
        print('BS')

