{"code": "import sys
import math

def count_23_integers(l, r):
    count = 0
    # Generate all possible 2^x values up to r
    x = 0
    while True:
        val2 = 2 ** x
        if val2 > r:
            break
        # For each val2, find all possible 3^y such that val2 * 3^y is between l and r
        y = 0
        while True:
            val3 = 3 ** y
            product = val2 * val3
            if product > r:
                break
            if product >= l:
                count += 1
            y += 1
        x += 1
    return count

if __name__ == '__main__':
    l, r = map(int, sys.stdin.read().split())
    print(count_23_integers(l, r))"}

