    for i in range(K):
        if decided:
            continue
        I_pose = I_poses[i]
        N_pose = N_poses[i]

        # Check for attack poses
        if I_pose == 'kougekida' and N_pose == 'kougekida':
            if I_attack == 0 and N_attack == 0:
                # No result
                pass
            else:
                if I_attack > N_attack:
                    result = 'Isono-kun'
                elif I_attack < N_attack:
                    result = 'Nakajima-kun'
                else:
                    # Same attack power
                    pass
                decided = True
        elif I_pose == 'kougekida':
            # I is attacking, N is not
            if I_attack == 0:
                # I loses, Nakajima wins
                result = 'Nakajima-kun'
                decided = True
            else:
                # I wins
                result = 'Isono-kun'
                decided = True
        elif N_pose == 'kougekida':
            # N is attacking, I is not
            if N_attack == 0:
                # N loses, I wins
                result = 'Isono-kun'
                decided = True
            else:
                # N wins
                result = 'Nakajima-kun'
                decided = True
        else:
            # Both are defense or pool
            # Check if either is pool
            if I_pose == 'tameru':
                # I is pool, N is not attack
                # Check if N is attacking. But N's pose is not attack, so no.
