{"code": "import sys

def is_valid(num_str):
    if len(num_str) == 0:
        return False
    if len(num_str) > 1 and num_str[0] == '0':
        return False
    if len(num_str) > 12:
        return False
    return True

def max_sum(s):
    max_sum = -1
    L = len(s)
    for a in range(1, L-2):
        first = s[:a]
        if not is_valid(first):
            continue
        for b in range(a+1, L-1):
            second = s[a:b]
            if not is_valid(second):
                continue
            for c in range(b+1, L):
                third = s[b:c]
                fourth = s[c:]
                if not is_valid(third) or not is_valid(fourth):
                    continue
                # Now compute the sum
                sum_val = int(first) + int(second) + int(third) + int(fourth)
                if sum_val > max_sum:
                    max_sum = sum_val
    return max_sum if max_sum != -1 else 'unlucky'

def main():
    N = int(sys.stdin.readline())
    for _ in range(N):
        s = sys.stdin.readline().strip()
        result = max_sum(s)
        print(result)

if __name__ == '__main__':
    main()"}

