{"code": "import sys
import itertools

def is_valid_k(S, k):
    new_set = set()
    for s in S:
        new_set.add(s ^ k)
    return new_set == S

def find_min_k(S):
    n = len(S)
    if n == 0:
        return -1

    # Generate all possible k candidates from pairs in S
    candidates = set()
    for s in S:
        for t in S:
            candidates.add(s ^ t)

    # Also include 0, but since k must be positive, we'll filter it out later
    candidates.add(0)

    # Check each candidate
    for k in sorted(candidates):
        if k == 0:
            continue
        if is_valid_k(S, k):
            return k
    return -1

def main():
    t = int(sys.stdin.readline())
    for _ in range(t):
        n = int(sys.stdin.readline())
        S = list(map(int, sys.stdin.readline().split()))
        S_set = set(S)
        result = find_min_k(S_set)
        print(result)

if __name__ == '__main__':
    main()"}

